#include <stdio.h>
#include <stdlib.h>

int is_possible(long long *c, int n, int a, long long limit) {
    int painters = 1;
    long long total = 0;
    for (int i = 0; i < n; ++i) {
        if (c[i] > limit) return 0;
        if (total + c[i] > limit) {
            ++painters;
            total = c[i];
            if (painters > a) return 0;
        } else {
            total += c[i];
        }
    }
    return 1;
}

int main() {
    const long long MOD = 10000003LL;
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int A, B, N; scanf("%d %d %d", &A, &B, &N);
        long long *C = (long long*)malloc(N * sizeof(long long));
        long long low = 0, high = 0;
        for (int i = 0; i < N; ++i) {
            scanf("%lld", &C[i]);
            if (C[i] > low) low = C[i];
            high += C[i];
        }
        long long ans = high;
        while (low <= high) {
            long long mid = low + (high - low) / 2;
            if (is_possible(C, N, A, mid)) {
                ans = mid;
                high = mid - 1;
            } else {
                low = mid + 1;
            }
        }
        long long result = ((ans % MOD) * (B % MOD)) % MOD;
        printf("%lld\n", result);
        free(C);
    }
    return 0;
}

