import sys
MOD = 10000003

def possible(arr, a, limit):
    painters = 1
    total = 0
    for length in arr:
        if length > limit:
            return False
        if total + length > limit:
            painters += 1
            total = length
            if painters > a:
                return False
        else:
            total += length
    return True

def solve():
    data = list(map(int, sys.stdin.read().strip().split()))
    if not data:
        return
    idx = 0
    T = data[idx]; idx += 1
    out_lines = []
    for _ in range(T):
        A = data[idx]; B = data[idx+1]; N = data[idx+2]; idx += 3
        C = data[idx:idx+N]; idx += N
        low = max(C)
        high = sum(C)
        ans = high
        while low <= high:
            mid = (low + high) // 2
            if possible(C, A, mid):
                ans = mid
                high = mid - 1
            else:
                low = mid + 1
        out_lines.append(str((ans * B) % MOD))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

